#!/bin/bash
# Apply Hajirai generalization updates (strip Aetrex branding, remove Chat Server URL field).
# Run this from the root of your hajirai project (~/shopify-apps/hajirai).
set -e

# Safety check
if [ ! -d "app/routes" ] || [ ! -d "extensions" ] || [ ! -d "prisma" ]; then
  echo "ERROR: Run this from the root of your hajirai project (~/shopify-apps/hajirai)."
  exit 1
fi

echo "Extracting updated files..."
echo "" | base64 -d | tar xz

echo "Removing unused config.jsx app-proxy route..."
rm -f app/routes/config.jsx

echo "Running prisma migrate (drops chatServerUrl column)..."
npx prisma migrate dev --name remove_chat_server_url

echo ""
echo "Done. Files updated:"
echo "  - extensions/hajirai-chat-widget/assets/hajirai-chat-widget.js"
echo "  - extensions/hajirai-chat-widget/blocks/hajirai_chat.liquid"
echo "  - app/routes/app._index.jsx"
echo "  - app/routes/app.api-keys.jsx"
echo "  - app/routes/app.knowledge.jsx"
echo "  - prisma/schema.prisma"
echo "  - app/routes/config.jsx (deleted)"
echo ""
echo "Next steps:"
echo "  1. Restart 'shopify app dev'"
echo "  2. Test the widget"
echo "  3. git add -A && git commit -m 'Generalize for public app store' && git push"
